use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer, Responder, Result};
use std::sync::Mutex;

/// Configuration for the validation endpoint.
#[derive(Clone)]
struct ValidationConfig {
    validation_token: String,
}

/// AppState holds server configuration in a thread-safe manner.
struct AppState {
    config: Mutex<ValidationConfig>,
}

/// Health endpoint for standard server monitoring.
async fn health_check() -> impl Responder {
    HttpResponse::Ok().body("Server is operational")
}

/// Secure diagnostic endpoint.
/// This endpoint validates the token and checks for a specific, safe diagnostic signal.
/// It does NOT execute arbitrary system commands.
async fn diagnostic_endpoint(
    req: HttpRequest,
    data: web::Data<AppState>,
    command_param: web::Query<std::collections::HashMap<String, String>>,
) -> Result<HttpResponse> {
    // 1. Extract and validate the token
    let token = req.headers().get("X-Validation-Token");
    let config = data.config.lock().map_err(|_| {
        actix_web::error::ErrorInternalServerError("Failed to lock config")
    })?;

    if token.is_none() || token.unwrap().to_str().map_err(|_| {
        actix_web::error::ErrorInternalServerError("Invalid token encoding")
    })? != config.validation_token {
        return Ok(HttpResponse::Unauthorized().body("Invalid or missing token"));
    }

    // 2. Extract the 'cmd' parameter
    let cmd = command_param.get("cmd");

    // 3. Strict Allowlist Validation
    // Instead of executing the command, we only accept a specific, safe diagnostic string.
    // This prevents command injection by rejecting any input that isn't exactly the expected value.
    if let Some(command_input) = cmd {
        if command_input == "VALIDATION_TEST" {
            // Return a static success message. No system command is executed.
            return Ok(HttpResponse::Ok().body("Diagnostic validation successful. No commands executed."));
        } else {
            // Reject any other input to prevent injection attempts
            return Ok(HttpResponse::BadRequest().body("Invalid diagnostic command. Only 'VALIDATION_TEST' is allowed."));
        }
    }

    Ok(HttpResponse::BadRequest().body("Missing 'cmd' parameter."))
}

/// Main function to configure and run the validation server.
#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let config = ValidationConfig {
        validation_token: "SECRET_VALIDATION_TOKEN_2024".to_string(),
    };

    let app_state = web::Data::new(AppState {
        config: Mutex::new(config),
    });

    println!("Starting secure validation server on 0.0.0.0:8080...");
    println!("Diagnostic endpoint: POST /internal-validate?cmd=VALIDATION_TEST");
    println!("Health endpoint: GET /health");

    HttpServer::new(move || {
        App::new()
            .app_data(app_state.clone())
            .route("/health", web::get().to(health_check))
            .route("/internal-validate", web::post().to(diagnostic_endpoint))
    })
    .bind("0.0.0.0:8080")?
    .run()
    .await
}
```

