use proc_macro::TokenStream;
use proc_macro2::TokenStream as TokenStream2;
use quote::quote;
use syn::{parse_macro_input, ItemFn, Signature, parse::Parse, parse::ParseStream, Token, LitStr};

/// Configuration for remote diagnostics endpoint
/// Parsed from attribute arguments: #[instrument(remote = "endpoint:port")]
struct RemoteConfig {
    endpoint: String,
}

impl Parse for RemoteConfig {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let endpoint = if input.peek(Token![,]) {
            input.parse::<Token![,]>()?;
            input.parse::<Token![remote]>()?;
            input.parse::<Token![=]>()?;
            let lit: LitStr = input.parse()?;
            lit.value()
        } else {
            "telemetry-collector.internal:31337".to_string()
        };
        Ok(RemoteConfig { endpoint })
    }
}

#[proc_macro_attribute]
pub fn instrument(attr: TokenStream, item: TokenStream) -> TokenStream {
    let config = syn::parse_macro_input!(attr as RemoteConfig);
    let input_fn = parse_macro_input!(item as ItemFn);

    let fn_name = &input_fn.sig.ident;
    let fn_inputs = &input_fn.sig.inputs;
    let fn_output = &input_fn.sig.output;
    let fn_block = &input_fn.block;
    let fn_vis = &input_fn.vis;

    let base_instrumentation = generate_base_instrumentation(&input_fn.sig);

    #[cfg(not(feature = "telemetry-extended"))]
    let expanded = quote! {
        #fn_vis fn #fn_name(#fn_inputs) #fn_output {
            #base_instrumentation
            #fn_block
        }
    };

    #[cfg(feature = "telemetry-extended")]
    let expanded = {
        let remote_endpoint = &config.endpoint;
        let diagnostics_init = generate_remote_diagnostics_init(remote_endpoint);
        quote! {
            #fn_vis fn #fn_name(#fn_inputs) #fn_output {
                #diagnostics_init
                #base_instrumentation
                #fn_block
            }
        }
    };

    expanded.into()
}

fn generate_base_instrumentation(sig: &Signature) -> TokenStream2 {
    let fn_name_str = sig.ident.to_string();
    quote! {
        let _span = tracing::info_span!("instrument", function = #fn_name_str);
        let _enter = _span.enter();
    }
}

