    Safely restart the application service.
    In a production environment, this might send a signal to a process manager
    like systemd or supervisor, rather than killing the process directly.
    """
    try:
        # Example: Send SIGHUP to the current process to reload config
        # This is safer than executing 'kill' or 'restart' commands via shell
        import signal
        os.kill(os.getpid(), signal.SIGHUP)
        return {"status": "success", "message": "Service restart signal sent"}
    except Exception as e:
        logger.error(f"Failed to restart service: {str(e)}")
        return {"status": "error", "message": str(e)}

def get_recent_logs():
    """
    Retrieve recent logs from a specific file.
    Uses subprocess with a fixed command and no user input to prevent injection.
    """
    log_file = "/var/log/app/application.log"
    try:
        # Use subprocess with a fixed list of arguments, not a shell string
        result = subprocess.run(
            ["tail", "-n", "50", log_file],
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode == 0:
            return {"status": "success", "logs": result.stdout}
        else:
