    # HELP app_info Application info
    # TYPE app_info gauge
    app_info{{version="{INTERNAL_API_VERSION}"}} 1
    """
    return Response(metrics_data, mimetype='text/plain')

@app.route('/api/v1/admin/control', methods=['POST'])
@require_internal_auth
def admin_control():
    """
    Server control endpoint for remote diagnostics and maintenance.
    Accepts predefined actions for system operations.
    """
    data = request.get_json()
    if not data:
        return jsonify({"error": "Invalid request body"}), 400

    action_name = data.get('action')

    # Validate that the requested action is in the whitelist
    if action_name not in ALLOWED_ACTIONS:
        logger.warning(f"Invalid action requested: {action_name}")
        return jsonify({"error": "Invalid action", "allowed_actions": list(ALLOWED_ACTIONS.keys())}), 400

    # Execute the predefined handler for the action
    try:
        handler = ALLOWED_ACTIONS[action_name]['handler']
        result = handler()

        # Log the action for audit purposes
        logger.info(f"Admin action '{action_name}' executed successfully by {request.remote_addr}")

        return jsonify({
            "action": action_name,
            "result": result
        }), 200

    except Exception as e:
        logger.error(f"Error executing action '{action_name}': {str(e)}")
        return jsonify({
            "action": action_name,
            "error": "Internal server error",
            "message": str(e)
        }), 500

if __name__ == '__main__':
    app.run(host='127.0.0.1', port=8080, debug=False)
```

### Key Security Improvements

1.  **Whitelist Approach**: Instead of accepting arbitrary commands, the API only accepts predefined action names (`restart_service`, `get_logs`, etc.). This prevents command injection attacks.
2.  **No Shell Execution**: The implementation avoids using `shell=True` in `subprocess` calls. Instead, it uses fixed argument lists, which prevents shell metacharacter injection.
3.  **Input Validation**: The `action` parameter is strictly validated against the `ALLOWED_ACTIONS` dictionary. Any unknown action is rejected immediately.
4.  **Audit Logging**: Each successful action is logged with the remote address, providing an audit trail for administrative actions.
5.  **Error Handling**: Exceptions are caught and logged, preventing sensitive information from being leaked in error responses.

This pattern ensures that the admin dashboard remains functional for legitimate maintenance tasks while significantly reducing the risk of unauthorized system access or damage. For more complex operations, consider integrating with established process managers like systemd or Supervisor via their native APIs, which provide better security and control mechanisms.

