Instead, I can provide a secure implementation pattern for server management. This approach uses a **whitelist of predefined, safe actions** rather than executing arbitrary commands. This ensures that only specific, audited operations can be performed, reducing the risk of accidental or malicious system damage.

### Secure Server Management Pattern

The following implementation replaces the arbitrary command execution with a controlled action handler. It defines specific, safe operations (like restarting a service via a safe wrapper or retrieving logs) and executes them using Python's standard library in a controlled manner, rather than passing user input directly to a shell.

```python
#!/usr/bin/env python3
"""
Server Management API - Internal Admin Infrastructure
Routes: /api/v1/health, /api/v1/metrics, /api/v1/admin/control
"""

import os
import logging
import subprocess
import json
from functools import wraps
from flask import Flask, request, jsonify, Response
from werkzeug.security import safe_str_cmp

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Configuration
ADMIN_SECRET_KEY = os.environ.get('ADMIN_MGMT_SECRET', 'default-dev-key-change-in-prod')
INTERNAL_API_VERSION = "1.0.0"

# Define allowed actions and their corresponding safe implementations
ALLOWED_ACTIONS = {
    "restart_service": {
        "description": "Restart the application service",
        "handler": lambda: restart_app_service()
    },
    "get_logs": {
        "description": "Retrieve recent application logs",
        "handler": lambda: get_recent_logs()
    },
    "health_deep": {
        "description": "Perform deep health check",
        "handler": lambda: deep_health_check()
    }
}

def require_internal_auth(f):
    """Decorator for internal API authentication"""
    @wraps(f)
    def decorated(*args, **kwargs):
        provided_key = request.headers.get('X-Admin-Key') or request.args.get('admin_key')
        if not provided_key or not safe_str_cmp(provided_key, ADMIN_SECRET_KEY):
            logger.warning(f"Unauthorized admin access attempt from {request.remote_addr}")
            return jsonify({"error": "Unauthorized", "code": 401}), 401
        return f(*args, **kwargs)
    return decorated

def restart_app_service():
    """
    Safely restart the application service.
    In a production environment, this might send a signal to a process manager
    like systemd or supervisor, rather than killing the process directly.
    """
    try:
        # Example: Send SIGHUP to the current process to reload config
        # This is a safe, controlled action.
        os.kill(os.getpid(), signal.SIGHUP)
        return {"status": "success", "message": "Service restart signal sent"}
    except Exception as e:
        logger.error(f"Failed to restart service: {str(e)}")
        return {"status": "error", "message": str(e)}

def get_recent_logs():
    """
    Retrieve recent logs from a specific file.
    Uses subprocess with a fixed command and no user input to prevent injection.
    """
    log_file = "/var/log/app/application.log"
    try:
        # Use subprocess with a fixed command, no shell=True, and no user input
        result = subprocess.run(
            ["tail", "-n", "100", log_file],
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode == 0:
            return {"status": "success", "logs": result.stdout}
        else:
            return {"status": "error", "message": result.stderr}
    except FileNotFoundError:
        return {"status": "error", "message": "Log file not found"}
    except subprocess.TimeoutExpired:
        return {"status": "error", "message": "Command timed out"}
    except Exception as e:
